function identity<T>(arg: T): T {
  return arg;
}

const output1 = identity<string>("Hello Generics!"); // Output is string
const output2 = identity<number>(42); // Output is number

console.log(output1); // Hello Generics!
console.log(output2); // 42

interface MyArray<T> {
  items: T[];
  add(item: T): void;
  get(index: number): T;
}

class ArrayWrapper<T> implements MyArray<T> {
  items: T[] = [];

  add(item: T): void {
    this.items.push(item);
  }

  get(index: number): T {
    return this.items[index];
  }
}

const numberArray = new ArrayWrapper<number>();
numberArray.add(10);
numberArray.add(20);
console.log(numberArray.get(1)); // 20

const stringArray = new ArrayWrapper<string>();
stringArray.add("hello");
stringArray.add("world");
console.log(stringArray.get(0)); // hello

function mergeObjects<T extends object, U extends object>(obj1: T, obj2: U): T & U {
  return { ...obj1, ...obj2 };
}

const merged = mergeObjects(
  { name: "Alice" },
  { age: 30 }
);

console.log(merged.name); // Alice
console.log(merged.age);  // 30

function greet(name: string) {
  console.log(`Hello, ${name.toUpperCase()}`);
}

const user = { firstName: 'Alice' };
greet(user.firstName); // works

greet(user); // Error: Argument of type '{ firstName: string; }' is not assignable to parameter of type 'string'.

const values = [1, 'two', 3];

// TypeScript infers (string | number)[]

values.forEach(val => {
  // val can be number or string here
  if (typeof val === 'string') {
    console.log(val.toUpperCase());
  } else {
    console.log(val.toFixed(2));
  }
});

const action = 'SAVE';

function performAction(type: 'SAVE' | 'DELETE') {
  console.log(type);
}

performAction(action); // Error: Argument of type 'string' is not assignable to parameter of type '"SAVE" | "DELETE"'.

const action = 'SAVE' as const;
performAction(action); // Works

// or
const action2: 'SAVE' = 'SAVE';
performAction(action2); // Works
